using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var openAiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException("Set the OPENAI_API_KEY environment variable.");
var searchApiKey = Environment.GetEnvironmentVariable("SEARCH_API_KEY"); // optional: Brave Search API key
var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\n🔍 Research Agent starting – topic: \"{topic}\"\n");

// --- Tool instances ---
var notepad = new Notepad();
var webSearch = new WebSearcher(searchApiKey);

// --- Build the chat client with tool support ---
IChatClient client = new OpenAIClient(openAiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(webSearch.Search),
        AIFunctionFactory.Create(notepad.AddNote),
        AIFunctionFactory.Create(notepad.GetNotes),
    ],
    Temperature = 0.3f,
};

// --- Agent loop ---
List<ChatMessage> history =
[
    new(ChatRole.System, """
        You are a research agent. Your goal is to thoroughly research the given topic
        and produce a well-structured summary.

        Workflow:
        1. Break the topic into 2-3 key questions.
        2. For each question, call the search tool to find information.
        3. Record important findings with the note-taking tool.
        4. After gathering enough information, review your notes and produce a final
           markdown summary with sections, key facts, and source URLs.

        Always cite sources. When you are done researching, output your final summary
        directly — do not call any more tools.
        """),
    new(ChatRole.User, $"Please research the following topic and summarize your findings:\n\n{topic}"),
];

const int maxIterations = 20;

for (var i = 0; i < maxIterations; i++)
{
    var response = await client.GetResponseAsync(history, chatOptions);

    // Append all response messages to history
    foreach (var msg in response.Messages)
        history.Add(msg);

    // If the model made no tool calls, we have the final answer
    var lastAssistant = response.Messages.LastOrDefault(m => m.Role == ChatRole.Assistant);
    if (lastAssistant is not null && !lastAssistant.Contents.OfType<FunctionCallContent>().Any())
    {
        Console.WriteLine("═══════════════════════════════════════");
        Console.WriteLine("  📝  RESEARCH SUMMARY");
        Console.WriteLine("═══════════════════════════════════════\n");
        Console.WriteLine(lastAssistant.Text);
        break;
    }
}

// Show collected notes
if (notepad.Notes.Count > 0)
{
    Console.WriteLine("\n───────────────────────────────────────");
    Console.WriteLine("  🗒️  RAW NOTES");
    Console.WriteLine("───────────────────────────────────────");
    foreach (var (j, note) in notepad.Notes.Select((n, i) => (i + 1, n)))
        Console.WriteLine($"  {j}. {note}");
}

return;

// --- Helpers ---
static string PromptForTopic()
{
    Console.Write("Enter a research topic: ");
    var input = Console.ReadLine()?.Trim();
    return string.IsNullOrEmpty(input)
        ? "Recent advances in renewable energy storage technology"
        : input;
}

// ────────────────────────────────────────────────────────────────────
//  Tools
// ────────────────────────────────────────────────────────────────────

/// <summary>Web search tool – uses Brave Search API when available, otherwise returns a placeholder.</summary>
sealed class WebSearcher(string? apiKey)
{
    private static readonly HttpClient Http = new();

    [Description("Searches the web for the given query and returns a list of result snippets with URLs.")]
    public async Task<string> Search(
        [Description("The search query string")] string query,
        [Description("Maximum number of results to return")] int maxResults = 5)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");

        if (!string.IsNullOrEmpty(apiKey))
            return await SearchBrave(query, maxResults);

        return SimulatedSearchResult(query);
    }

    private async Task<string> SearchBrave(string query, int maxResults)
    {
        var request = new HttpRequestMessage(HttpMethod.Get,
            $"https://api.search.brave.com/res/v1/web/search?q={Uri.EscapeDataString(query)}&count={maxResults}");
        request.Headers.Add("X-Subscription-Token", apiKey);
        request.Headers.Add("Accept", "application/json");

        var response = await Http.SendAsync(request);
        response.EnsureSuccessStatusCode();

        using var doc = await JsonDocument.ParseAsync(await response.Content.ReadAsStreamAsync());
        var results = doc.RootElement
            .GetProperty("web")
            .GetProperty("results");

        var lines = new List<string>();
        foreach (var r in results.EnumerateArray().Take(maxResults))
        {
            var title = r.GetProperty("title").GetString();
            var url = r.GetProperty("url").GetString();
            var snippet = r.TryGetProperty("description", out var d) ? d.GetString() : "";
            lines.Add($"- **{title}**\n  {snippet}\n  URL: {url}");
        }

        return lines.Count > 0
            ? string.Join("\n\n", lines)
            : "No results found.";
    }

    private static string SimulatedSearchResult(string query) =>
        $"""
        [Simulated results for "{query}" — set SEARCH_API_KEY for live Brave Search results]

        - **Wikipedia: {query}**
          Comprehensive overview of {query} covering history, current state, and future outlook.
          URL: https://en.wikipedia.org/wiki/{Uri.EscapeDataString(query.Replace(' ', '_'))}

        - **Recent Developments in {query}**
          A 2025 review article discussing the latest breakthroughs and trends.
          URL: https://example.com/review-{Uri.EscapeDataString(query.Replace(' ', '-'))}

        - **{query} — Nature**
          Peer-reviewed research on the subject with detailed analysis.
          URL: https://nature.com/articles/{Uri.EscapeDataString(query.Replace(' ', '-'))}
        """;
}

/// <summary>Note-taking tool for the agent to record findings.</summary>
sealed class Notepad
{
    public List<string> Notes { get; } = [];

    [Description("Saves a note capturing an important finding from the research. Use this to record key facts, data points, or insights.")]
    public string AddNote(
        [Description("The text of the note to save")] string note)
    {
        Notes.Add(note);
        Console.WriteLine($"  📌 Note #{Notes.Count} saved");
        return $"Note #{Notes.Count} saved successfully.";
    }

    [Description("Returns all notes taken so far, useful for reviewing findings before writing a summary.")]
    public string GetNotes()
    {
        if (Notes.Count == 0)
            return "No notes taken yet.";

        return string.Join("\n", Notes.Select((n, i) => $"{i + 1}. {n}"));
    }
}

